ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
    "jsonrpc": "2.0",
    "id": vars.rpcReq.id,
    "result": {
        "name": "Broker Agent",
        "description": "マルチエージェントオーケストレーター。複数のドメインエージェントに問い合わせて結論を集約 (LLM非使用)",
        "url": "http://localhost:5180/",
        "version": "0.1.0",
        "provider": {
            "organization": "agent-center demo",
            "url": "http://localhost:8000/"
        },
        "capabilities": {
            "streaming": false,
            "pushNotifications": false,
            "stateTransitionHistory": false
        },
        "defaultInputModes": ["text"],
        "defaultOutputModes": ["text"],
        "skills": [
            {
                "id": "handle_delivery_delay_claim",
                "name": "Handle Delivery Delay Claim",
                "description": "納期遅延クレームを受け、配送状況・在庫・SLA判定をまとめて返す",
                "tags": ["broker", "orchestration", "claim"]
            }
        ]
    }
}

%dw 2.0
output application/json
---
{
    "jsonrpc": "2.0",
    "id": vars.rpcReq.id,
    "result": {
        "status": { "state": "completed" },
        "messages": [
            {
                "role": "agent",
                "parts": [{ "kind": "text", "text": "> 現在は **クレーム** / **納期遅延** 系のキーワードに対応しています。\n>\n> 例: `納期遅延クレーム` `商品が届かない` `トラブルが起きた` `お客さんから苦情` など" }],
                "messageId": uuid()
            }
        ]
    }
}

%dw 2.0
output application/json
---
{
    jsonrpc: "2.0",
    id: "broker-" ++ uuid(),
    method: "message/send",
    params: {
        message: {
            role: "user",
            parts: [{kind: "text", text: "注文 " ++ (vars.orderId default "?") ++ " の配送ステータスは？"}],
            messageId: uuid()
        }
    }
}

%dw 2.0
output application/json
---
{
    jsonrpc: "2.0",
    id: "broker-" ++ uuid(),
    method: "message/send",
    params: {
        message: {
            role: "user",
            parts: [{kind: "text", text: "注文 " ++ (vars.orderId default "?") ++ " の遅延理由を教えて"}],
            messageId: uuid()
        }
    }
}

%dw 2.0
output application/json
---
{
    jsonrpc: "2.0",
    id: "broker-" ++ uuid(),
    method: "message/send",
    params: {
        message: {
            role: "user",
            parts: [{kind: "text", text: "商品 " ++ (vars.productCode default "?") ++ " の入荷予定は？"}],
            messageId: uuid()
        }
    }
}

%dw 2.0
output application/json
---
{
    jsonrpc: "2.0",
    id: "broker-" ++ uuid(),
    method: "message/send",
    params: {
        message: {
            role: "user",
            parts: [{kind: "text", text: "注文 " ++ (vars.orderId default "?") ++ "、商品 " ++ (vars.productCode default "?") ++ "、配送遅延中、SLA違反か判定して"}],
            messageId: uuid()
        }
    }
}
